 37→	@Transform(({ value }: { value: number[] | string }) => {
 38→		if (Array.isArray(value)) return value;
 39→		if (typeof value === 'string') {
 40→			try {
 41→				return JSON.parse(value) as number[];
 42→			} catch {
 43→				return [];
