 42→	async findByStyleId({
 43→		styleId,
 44→	}: {
 45→		styleId: IStyleBase['style_id'];
 46→	}): Promise<IStyleBase | null> {
 47→		try {
 48→			const result = await this.knexRead<BaseStyleDto>(this.tableName)
 49→				.where({ style_id: styleId })
 50→				.whereNull('deleted_at')
 51→				.first()
 52→				.then((result) => {
 53→					if (!result) {
 54→						return null;
 55→					}
 56→
 57→					return {
 58→						// eslint-disable-next-line
 59→						...result,
 60→						categories_ids:
 61→							typeof result.categories_ids === 'string'
 62→								? (JSON.parse(result.categories_ids) as number[])
 63→								: result.categories_ids,
 64→						categories_with_parents_ids:
 65→							typeof result.categories_with_parents_ids === 'string'
 66→								? (JSON.parse(result.categories_with_parents_ids) as number[])
 67→								: result.categories_with_parents_ids,
 68→					};
 69→				});
 70→
 71→			if (!result) {
 72→				this.logger.warn(`No style found for styleId ${styleId}`);
 73→				return null;
 74→			}
 75→
 76→			this.logger.debug(`Found style for styleId ${styleId}`);
 77→
 78→			const parsedData = this.parseStyleData({
 79→				styleData: result as unknown as IStyleBase,
 80→			});
 81→			const dto = plainToInstance(BaseStyleDto, parsedData);
 82→			const errors = await validate(dto);
 83→			if (errors.length > 0) {
 84→				this.logger.error(
 85→					`Validation failed for style data: ${this.formatValidationErrors({ errors })}`,
 86→				);
 87→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 88→			}
 89→
 90→			return parsedData;
 91→		} catch (error) {
 92→			this.logger.error(
 93→				`Failed to find style for styleId ${styleId}: ${(error as Error).message}`,
 94→			);
 95→			throw error;
 96→		}
 97→	}
