 99→	async findMostPopularByCategories({
100→		categoryIds,
101→		limit = 5,
102→		excludeIds,
103→	}: {
104→		categoryIds: number[];
105→		limit?: number;
106→		excludeIds?: number[];
107→	}): Promise<IStyleBase[]> {
108→		try {
109→			const allResults: IStyleBase[] = [];
110→
111→			for (const categoryId of categoryIds) {
112→				let query = this.knexRead<BaseStyleDto>(this.tableName)
113→					.where('primary_category_id', categoryId)
114→					.whereNull('deleted_at');
115→
116→				if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
117→					query = query
118→						.whereNotNull('primary_category_id')
119→						.whereNotIn(
120→							'primary_category_id',
121→							FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
122→						);
123→				}
124→
125→				if (excludeIds?.length) {
126→					query = query.whereNotIn('style_id', excludeIds);
127→				}
128→
129→				const styles = await query.orderBy('purchases_count', 'desc').limit(limit);
130→
131→				const results = styles.map((style) => ({
132→					// eslint-disable-next-line
133→					...style,
134→					categories_ids:
135→						typeof style.categories_ids === 'string'
136→							? (JSON.parse(style.categories_ids) as number[])
137→							: style.categories_ids,
138→					categories_with_parents_ids:
139→						typeof style.categories_with_parents_ids === 'string'
140→							? (JSON.parse(style.categories_with_parents_ids) as number[])
141→							: style.categories_with_parents_ids,
142→				}));
143→
144→				const mappedResults = await Promise.all(
145→					results.map(async (result) => {
146→						const parsedData = this.parseStyleData({
147→							styleData: result as unknown as IStyleBase,
148→						});
149→						const dto = plainToInstance(BaseStyleDto, parsedData);
150→						const errors = await validate(dto);
151→						if (errors.length > 0) {
152→							this.logger.error(
153→								`Validation failed for style data: ${this.formatValidationErrors({ errors })}`,
154→							);
155→							throw new Error(
156→								`Validation failed: ${this.formatValidationErrors({ errors })}`,
157→							);
158→						}
159→						return parsedData;
160→					}),
161→				);
162→				allResults.push(...mappedResults);
163→			}
164→
165→			this.logger.debug(
166→				`Found ${allResults.length} popular styles for categories ${categoryIds.join(', ')}`,
167→			);
168→			return allResults;
169→		} catch (error) {
170→			this.logger.error(
171→				`Failed to find popular styles for categories ${categoryIds.join(', ')}: ${(error as Error).message}`,
172→			);
173→			throw error;
174→		}
175→	}
