189→				style_id: number;
190→				purchases_count: number;
191→			}[] = [];
192→
193→			for (const categoryId of categoryIds) {
194→				let query = this.knexRead<BaseStyleDto>(this.tableName)
195→					.select('root_category_id', 'style_id', 'purchases_count')
196→					.where('root_category_id', categoryId)
197→					.whereNull('deleted_at');
198→
199→				if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
