203→							'primary_category_id',
204→							FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
205→						);
206→				}
207→
208→				if (excludeIds?.length) {
209→					query = query.whereNotIn('style_id', excludeIds);
210→				}
211→
212→				const results = await query.orderBy('purchases_count', 'desc').limit(limit);
213→
214→				allResults.push(
215→					...(results as {
216→						root_category_id: number;
217→						style_id: number;
218→						purchases_count: number;
219→					}[]),
