235→	async findMostPopularCategories({ limit = 4 }: { limit?: number }): Promise<number[]> {
236→		try {
237→			let query = this.knexRead<BaseStyleDto>(this.tableName)
238→				.select('primary_category_id')
239→				.whereNull('deleted_at')
240→				.whereNotNull('primary_category_id');
241→
242→			if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
243→				query = query.whereNotIn(
244→					'primary_category_id',
245→					FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
246→				);
247→			}
248→
249→			const results = await query
250→				.groupBy('primary_category_id')
251→				.orderByRaw('COUNT(*) desc')
252→				.limit(limit);
253→
254→			const categoryIds = results
255→				.map((result) => result.primary_category_id)
256→				.filter((id): id is number => id !== null);
257→			this.logger.debug(`Found ${categoryIds.length} most popular categories`);
258→			return categoryIds;
259→		} catch (error) {
260→			this.logger.error(
261→				`Failed to find most popular categories: ${(error as Error).message}`,
262→			);
263→			throw error;
264→		}
265→	}
