396→	async upsertStyle({
397→		data,
398→	}: {
399→		data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
400→	}): Promise<IStyleBase> {
401→		try {
402→			const dto = plainToInstance(BaseStyleDto, data);
403→			const errors = await validate(dto, { skipMissingProperties: true });
404→
405→			if (errors.length > 0) {
406→				this.logger.error(
407→					`Validation failed for style data: ${this.formatValidationErrors({ errors })}`,
408→				);
409→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
410→			}
411→
412→			const upsertedStyle: IStyleBase = await this.knexWrite.transaction(async (trx) => {
413→				const existing = await trx<IStyleBase>(this.tableName)
414→					.where({ style_id: data.style_id })
415→					.whereNull('deleted_at')
416→					.first();
417→
418→				if (existing) {
419→					const updateData: Record<string, unknown> = {
420→						updated_at: trx.fn.now(),
421→					};
422→
423→					Object.keys(data).forEach((key) => {
424→						if (key !== 'style_id') {
425→							if (
426→								key === 'categories_ids' ||
427→								key === 'categories_with_parents_ids' ||
428→								key === 'broad_category_names' ||
429→								key === 'sub_category_names' ||
430→								key === 'brand' ||
431→								key === 'sizes'
432→							) {
433→								updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
434→							} else {
435→								updateData[key] = data[key as keyof typeof data];
436→							}
437→						}
438→					});
439→
440→					await trx(this.tableName)
441→						.where({ style_id: data.style_id })
442→						.whereNull('deleted_at')
443→						.update(updateData);
444→				} else {
445→					const _id = randomUUID();
446→					const insertData: Record<string, unknown> = {
447→						_id,
448→						...data,
449→						style_id: data.style_id,
450→						primary_category_id: data.primary_category_id ?? null,
451→						root_category_id: data.root_category_id ?? null,
452→						purchases_count: data.purchases_count ?? 0,
453→						is_active: data.is_active ?? true,
454→						categories_ids: JSON.stringify(data.categories_ids ?? []),
455→						categories_with_parents_ids: JSON.stringify(
456→							data.categories_with_parents_ids ?? [],
457→						),
458→						broad_category_names: JSON.stringify(data.broad_category_names ?? []),
459→						sub_category_names: JSON.stringify(data.sub_category_names ?? []),
460→						brand: JSON.stringify(data.brand ?? []),
461→						sizes: JSON.stringify(data.sizes ?? []),
462→						created_at: trx.fn.now(),
463→						updated_at: trx.fn.now(),
464→					};
465→
466→					await trx(this.tableName).insert(insertData);
467→				}
468→
469→				if (data.categories_with_parents_ids !== undefined) {
470→					await this.syncStyleCategories({
471→						trx,
472→						styleId: data.style_id,
473→						categoryIds: data.categories_ids ?? [],
474→						categoriesWithParentsIds: data.categories_with_parents_ids ?? [],
