478→				const result = await trx<IStyleBase>(this.tableName)
479→					.where({ style_id: data.style_id })
480→					.whereNull('deleted_at')
481→					.first();
482→
483→				if (!result) {
484→					throw new Error(`Failed to upsert style with style ID ${data.style_id}`);
485→				}
486→
487→				return result;
488→			});
489→
490→			this.logger.debug(`Upserted style with style ID ${data.style_id}`);
491→			const plainData = instanceToPlain<BaseStyleDto>(upsertedStyle) as IStyleBase;
