526→	async upsertStyleWithTransaction({
527→		trx,
528→		data,
529→	}: {
530→		trx: Knex.Transaction;
531→		data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
532→	}): Promise<IStyleBase> {
533→		try {
534→			const dto = plainToInstance(BaseStyleDto, data);
535→			const errors = await validate(dto, { skipMissingProperties: true });
536→
537→			if (errors.length > 0) {
538→				this.logger.error(
539→					`Validation failed for style data: ${this.formatValidationErrors({ errors })}`,
540→				);
541→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
542→			}
543→
544→			const existing = await trx<IStyleBase>(this.tableName)
545→				.where({ style_id: data.style_id })
546→				.whereNull('deleted_at')
547→				.first();
548→
549→			if (existing) {
550→				const updateData: Record<string, unknown> = {
551→					updated_at: trx.fn.now(),
552→				};
553→
554→				Object.keys(data).forEach((key) => {
555→					if (key !== 'style_id') {
556→						if (
557→							key === 'categories_ids' ||
558→							key === 'categories_with_parents_ids' ||
559→							key === 'broad_category_names' ||
560→							key === 'sub_category_names' ||
561→							key === 'brand' ||
562→							key === 'sizes'
563→						) {
564→							updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
565→						} else {
566→							updateData[key] = data[key as keyof typeof data];
567→						}
568→					}
569→				});
570→
571→				await trx(this.tableName)
572→					.where({ style_id: data.style_id })
573→					.whereNull('deleted_at')
574→					.update(updateData);
575→			} else {
576→				const _id = randomUUID();
577→				const insertData: Record<string, unknown> = {
578→					_id,
579→					...data,
580→					categories_ids: JSON.stringify(data.categories_ids ?? []),
581→					categories_with_parents_ids: JSON.stringify(
582→						data.categories_with_parents_ids ?? [],
583→					),
584→					broad_category_names: JSON.stringify(data.broad_category_names ?? []),
585→					sub_category_names: JSON.stringify(data.sub_category_names ?? []),
586→					brand: JSON.stringify(data.brand ?? []),
587→					sizes: JSON.stringify(data.sizes ?? []),
588→					created_at: trx.fn.now(),
589→					updated_at: trx.fn.now(),
590→				};
591→
592→				await trx(this.tableName).insert(insertData);
593→			}
594→
595→			if (data.categories_with_parents_ids !== undefined) {
596→				await this.syncStyleCategories({
597→					trx,
598→					styleId: data.style_id,
599→					categoryIds: data.categories_ids ?? [],
600→					categoriesWithParentsIds: data.categories_with_parents_ids ?? [],
601→				});
602→			}
603→
604→			const result = await trx<IStyleBase>(this.tableName)
605→				.where({ style_id: data.style_id })
606→				.whereNull('deleted_at')
607→				.first();
608→
609→			if (!result) {
610→				throw new Error(`Failed to upsert style with style ID ${data.style_id}`);
611→			}
612→
613→			this.logger.debug(`Upserted style with style ID ${data.style_id}`);
614→			const plainData = instanceToPlain<BaseStyleDto>(result) as IStyleBase;
615→			return this.parseStyleData({ styleData: plainData });
616→		} catch (error: unknown) {
617→			const err = error instanceof Error ? error : new Error(String(error));
618→			this.logger.error(
619→				`Failed to upsert style with style ID ${data.style_id}: ${err.message}`,
620→			);
621→			throw err;
622→		}
623→	}
