625→	async saveCompleteStyle({
626→		styleData,
627→		colors,
628→		defaultUnitPrices,
629→	}: {
630→		styleData: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
631→		colors: Omit<IStyleColorCreate, 'style_id'>[];
632→		defaultUnitPrices: Omit<IDefaultUnitPriceCreate, 'style_id'>[];
633→	}): Promise<void> {
634→		try {
635→			await this.knexWrite.transaction(async (trx) => {
636→				await this.upsertStyleWithTransaction({ trx, data: styleData });
637→
638→				for (const color of colors) {
639→					await this.styleColorModel.upsertStyleWithTransaction({
640→						trx,
641→						data: {
642→							style_id: styleData.style_id,
643→							...color,
644→						},
645→					});
646→				}
647→
648→				for (const priceData of defaultUnitPrices) {
649→					await this.defaultUnitPriceModel.upsertWithTransaction({
650→						trx,
651→						data: {
652→							style_id: styleData.style_id,
653→							...priceData,
654→						},
655→					});
656→				}
657→			});
658→
659→			this.logger.debug(
660→				`Successfully saved complete style with ${colors.length} colors and ${defaultUnitPrices.length} prices for style ${styleData.style_id}`,
661→			);
662→		} catch (error: unknown) {
663→			const err = error instanceof Error ? error : new Error(String(error));
664→			this.logger.error(
665→				`Failed to save complete style ${styleData.style_id}: ${err.message}`,
666→			);
667→			throw err;
668→		}
669→
670→		try {
671→			await this.stylesMvModel.refreshForStyle({ styleId: styleData.style_id });
672→		} catch (error: unknown) {
673→			const err = error instanceof Error ? error : new Error(String(error));
674→			this.logger.warn(
675→				`Failed to refresh MV for style ${styleData.style_id}: ${err.message}. Style data was saved successfully.`,
676→			);
677→			bufferedRollbar.error({
678→				err,
679→				context: {
680→					styleId: styleData.style_id,
681→					context: 'saveCompleteStyle MV refresh',
682→				},
683→			});
684→		}
685→	}
686→
687→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
688→		return errors
689→			.map(
690→				(error) =>
691→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
692→			)
693→			.join('; ');
694→	}
