696→	private async syncStyleCategories({
697→		trx,
698→		styleId,
699→		categoryIds,
700→		categoriesWithParentsIds,
701→	}: {
702→		trx: Knex.Transaction;
703→		styleId: number;
704→		categoryIds: number[];
705→		categoriesWithParentsIds: number[];
706→	}): Promise<void> {
707→		await trx(TABLE_NAME_STYLE_CATEGORIES).where('style_id', styleId).delete();
708→
709→		if (categoriesWithParentsIds.length > 0) {
710→			const directSet = new Set(categoryIds);
711→
712→			await trx(TABLE_NAME_STYLE_CATEGORIES).insert(
713→				categoriesWithParentsIds.map((categoryId) => ({
714→					_id: randomUUID(),
715→					style_id: styleId,
716→					category_id: categoryId,
717→					is_parent: !directSet.has(categoryId),
718→				})),
719→			);
720→		}
721→	}
722→}
