			await service.softDelete({ userId: mockUser._id });

			expect(mockUserModel.softDelete).toHaveBeenCalledWith({ userId: mockUser._id });
		});
	});
});

import { Injectable } from '@nestjs/common';

import { UserModel } from '@modules/user/user.model';
import { IUserBase } from '@modules/user/types/user.base.interface';
import { IUserCreate } from '@modules/user/types/user.create.interface';

@Injectable()
export class UserService {
	constructor(private readonly userModel: UserModel) {}

	async findById({ userId }: { userId: IUserBase['_id'] }): Promise<IUserBase | null> {
		return this.userModel.findById({ userId });
	}

	async findByEmail({ email }: { email: IUserBase['email'] }): Promise<IUserBase | null> {
		return this.userModel.findByEmail({ email });
	}

	async create({ data }: { data: IUserCreate }): Promise<IUserBase> {
		return this.userModel.create({ data });
	}

	async updateLastLogin({ userId }: { userId: IUserBase['_id'] }): Promise<void> {
		return this.userModel.updateLastLogin({ userId });
	}

	async softDelete({ userId }: { userId: IUserBase['_id'] }): Promise<void> {
		return this.userModel.softDelete({ userId });
	}
}

